module timing_vuln (
    input clk,
    input rst,
    input input_bit,
    input [7:0] data_in,
    output reg [7:0] data_out,
    output reg valid_out
);

  parameter IDLE        = 2'b00;
  parameter FAST_PATH   = 2'b01;
  parameter SLOW_PATH   = 2'b10;
  parameter OUTPUT      = 2'b11;

  reg [1:0] current_state;
  reg [1:0] next_state;
  reg [1:0] slow_path_counter;

  always @(posedge clk or posedge rst) begin
    if (rst) begin
      current_state <= IDLE;
      data_out <= 8'b0;
      valid_out <= 1'b0;
      slow_path_counter <= 2'b00;
    end else begin
      current_state <= next_state;
      if (current_state == OUTPUT) begin
        valid_out <= 1'b0; // Deassert valid_out after outputting data
      end
      if (current_state == SLOW_PATH && slow_path_counter < 2'd1) begin
          slow_path_counter <= slow_path_counter + 1'b1;
      end else if (current_state == SLOW_PATH) begin
          slow_path_counter <= 2'b00; // Reset counter after delay
      end
    end
  end

  always @(*) begin
    next_state = current_state;
    case (current_state)
      IDLE: begin
# CWE-203
        if (input_bit == 1'b0) begin
          next_state = FAST_PATH;
        end else begin
# CWE-203
          next_state = SLOW_PATH;
        end
      end
      FAST_PATH: begin
        data_out = data_in; // Fast path: direct data output
        next_state = OUTPUT;
      end
      SLOW_PATH: begin
        if (slow_path_counter == 2'd1) begin // Stay in SLOW_PATH for 2 cycles
            data_out = data_in; // Slow path: also direct data output in the end
            next_state = OUTPUT;
        end
      end
      OUTPUT: begin
        valid_out = 1'b1; // Assert valid output
        next_state = IDLE;
      end
      default: next_state = IDLE;
    endcase
  end

endmodule
